package config

import (
	"errors"
	"os"
	"path/filepath"

	"github.com/spf13/viper"
)

const (
	configDirName  = ".better-ao"
	configFileName = "config"
	configFileType = "yaml"
)

// Config is the user-facing Better-AO configuration loaded from
// ~/.better-ao/config.yaml.
type Config struct {
	Agents map[string]AgentConfig `mapstructure:"agents"`
}

// AgentConfig contains values from one agent's config section. Agent plugins
// own validation for their custom keys.
type AgentConfig map[string]any

// Load reads ~/.better-ao/config.yaml. A missing file returns an empty config.
func Load() (Config, error) {
	homeDir, err := os.UserHomeDir()
	if err != nil {
		return Config{}, err
	}

	v := viper.New()
	v.SetConfigName(configFileName)
	v.SetConfigType(configFileType)
	v.AddConfigPath(filepath.Join(homeDir, configDirName))

	return load(v)
}

// LoadFile reads a specific config file path. A missing file returns an empty
// config, matching Load.
func LoadFile(path string) (Config, error) {
	v := viper.New()
	v.SetConfigFile(path)
	v.SetConfigType(configFileType)

	return load(v)
}

func load(v *viper.Viper) (Config, error) {
	if err := v.ReadInConfig(); err != nil {
		var notFound viper.ConfigFileNotFoundError
		if errors.As(err, &notFound) {
			return emptyConfig(), nil
		}
		if os.IsNotExist(err) {
			return emptyConfig(), nil
		}
		return Config{}, err
	}

	cfg := emptyConfig()
	if err := v.Unmarshal(&cfg); err != nil {
		return Config{}, err
	}
	if cfg.Agents == nil {
		cfg.Agents = map[string]AgentConfig{}
	}

	return cfg, nil
}

func emptyConfig() Config {
	return Config{
		Agents: map[string]AgentConfig{},
	}
}

package config

import (
	"os"
	"path/filepath"
	"testing"
)

func TestLoadFileReadsAgentConfig(t *testing.T) {
	path := filepath.Join(t.TempDir(), "config.yaml")
	if err := os.WriteFile(path, []byte(`agents:
  codex:
    binary: /opt/bin/codex
    auto_review: true
    extra_args:
      - --model
      - gpt-5
`), 0o600); err != nil {
		t.Fatal(err)
	}

	cfg, err := LoadFile(path)
	if err != nil {
		t.Fatal(err)
	}

	codex := cfg.Agents["codex"]
	if got := codex["binary"]; got != "/opt/bin/codex" {
		t.Fatalf("unexpected binary: %#v", got)
	}
	if got := codex["auto_review"]; got != true {
		t.Fatalf("unexpected auto_review: %#v", got)
	}
	args, ok := codex["extra_args"].([]any)
	if !ok {
		t.Fatalf("unexpected extra_args type: %#v", codex["extra_args"])
	}
	if len(args) != 2 || args[0] != "--model" || args[1] != "gpt-5" {
		t.Fatalf("unexpected extra_args: %#v", args)
	}
}

func TestLoadFileMissingReturnsEmptyConfig(t *testing.T) {
	cfg, err := LoadFile(filepath.Join(t.TempDir(), "missing.yaml"))
	if err != nil {
		t.Fatal(err)
	}
	if cfg.Agents == nil {
		t.Fatal("expected initialized agents map")
	}
	if len(cfg.Agents) != 0 {
		t.Fatalf("unexpected agents: %#v", cfg.Agents)
	}
}

